mapper.select:
select id, shipping_days_real, shipping_days_scheduled, delivery_status, late_risk, shipping_date,
shipping_mode, order_id
from logistics


        and shipping_days_real >= #{daysRealMin}


        and shipping_days_real <= #{daysRealMax}


        and shipping_days_scheduled >= #{daysScheduledMin}


        and shipping_days_scheduled <= #{daysScheduledMax}


        and delivery_status = #{deliveryStatus}


        and late_risk = #{lateRisk}


        and shipping_date >= #{shippingDateBegin}


        and shipping_date <= #{shippingDateEnd}



        and shipping_mode <= #{shippingMode}


        and order_id = #{orderId}
